import{_ as l,c as i,o as p,R as t}from"./chunks/framework.Cfz5bXfs.js";const v=JSON.parse('{"title":"VS Code","description":"","frontmatter":{},"headers":[],"relativePath":"tools/vs-code.md","filePath":"tools/vs-code.md","lastUpdated":1701681006000}'),e={name:"tools/vs-code.md"},o=t('<h1 id="vs-code" tabindex="-1">VS Code <a class="header-anchor" href="#vs-code" aria-label="Permalink to &quot;VS Code&quot;">​</a></h1><h2 id="一、vs-code-的常用快捷键" tabindex="-1">一、vs code 的常用快捷键 <a class="header-anchor" href="#一、vs-code-的常用快捷键" aria-label="Permalink to &quot;一、vs code 的常用快捷键&quot;">​</a></h2><ol><li><p>注释：</p><p>a. 单行注释：[ctrl+k,ctrl+c] 或 ctrl+/</p><p>b. 取消单行注释：[ctrl+k,ctrl+u] (按下ctrl不放，再按k + u)</p><p>c. 多行注释：[alt+shift+A]</p><p>d. 多行注释：/**</p></li><li><p>移动行：alt+up/down</p></li><li><p>显示/隐藏左侧目录栏 ctrl + b</p></li><li><p>复制当前行：shift + alt +up/down</p></li><li><p>删除当前行：shift + ctrl + k</p></li><li><p>控制台终端显示与隐藏：ctrl + ~</p></li><li><p>查找文件/安装vs code 插件地址：ctrl + p</p></li><li><p>代码格式化：shift + alt +f</p></li><li><p>新建一个窗口 : ctrl + shift + n</p></li><li><p>行增加缩进: ctrl + [</p></li><li><p>行减少缩进: ctrl + ]</p></li><li><p>裁剪尾随空格(去掉一行的末尾那些没用的空格) : ctrl + shift + x</p></li><li><p>字体放大/缩小: ctrl + ( + 或 - )</p></li><li><p>拆分编辑器 : ctrl + 1/2/3</p></li><li><p>切换窗口 : ctrl + shift + left/right</p></li><li><p>关闭编辑器窗口 : ctrl + w</p></li><li><p>关闭所有窗口 : ctrl + k + w</p></li><li><p>切换全屏 : F11</p></li><li><p>自动换行 : alt + z</p></li><li><p>显示git : ctrl + shift + g</p></li><li><p>全局查找文件：ctrl + shift + f</p></li><li><p>显示相关插件的命令(如：git log)：ctrl + shift + p</p></li><li><p>选中文字：shift + left / right / up / down</p></li><li><p>折叠代码： ctrl + k + 0-9 (0是完全折叠)</p></li><li><p>展开代码： ctrl + k + j (完全展开代码)</p></li><li><p>删除行 ： ctrl + shift + k</p></li><li><p>快速切换主题：ctrl + k / ctrl + t</p></li><li><p>快速回到顶部 ： ctrl + home</p></li><li><p>快速回到底部 : ctrl + end</p></li><li><p>格式化选定代码 ：ctrl + k / ctrl +f</p></li><li><p>选中代码 ： shift + 鼠标左键</p></li><li><p>多行同时添加内容（光标） ：ctrl + alt + up/down</p></li><li><p>全局替换：ctrl + shift + h</p></li><li><p>当前文件替换：ctrl + h</p></li><li><p>打开最近打开的文件：ctrl + r</p></li><li><p>打开新的命令窗：ctrl + shift + c</p></li></ol><h2 id="二、vs-code-的常用插件" tabindex="-1">二、vs code 的常用插件 <a class="header-anchor" href="#二、vs-code-的常用插件" aria-label="Permalink to &quot;二、vs code 的常用插件&quot;">​</a></h2><ol><li><p>Auto Rename Tag 修改html标签，自动帮你完成尾部闭合标签的同步修改，和webstorm一样。</p></li><li><p>Auto Close Tag 自动闭合HTML标签</p></li><li><p>Beautiful 格式化代码的工具</p></li><li><p>Dash Dash是MacOS的API文档浏览器和代码段管理器</p></li><li><p>Ejs Snippets ejs 代码提示</p></li><li><p>ESLint 检查javascript语法错误与提示</p></li><li><p>File Navigator 快速查找文件</p></li><li><p>Git History(git log) 查看git log</p></li><li><p>Gulp Snippets 写gulp时用到，gulp语法提示。</p></li><li><p>HTML CSS Support 在HTML标签上写class智能提示当前项目所支持的样式</p></li><li><p>HTML Snippets 超级好用且初级的H5代码片段以及提示</p></li><li><p>Debug for Chrome 让vs code映射chrome的debug功能，静态页面都可以用vscode来打断点调试、配饰稍微复杂一点</p></li><li><p>Document this Js的注释模板</p></li><li><p>jQuery Code Snippets jquery提示工具</p></li><li><p>Html2jade html模板转pug模板</p></li><li><p>JS-CSS-HTML Formatter 格式化</p></li><li><p>Npm intellisense require 时的包提示工具</p></li><li><p>Open in browser 打开默认浏览器</p></li><li><p>One Dark Theme 一个vs code的主题</p></li><li><p>Path Intellisense 自动路径补全、默认不带这个功能</p></li><li><p>Project Manager 多个项目之间快速切换的工具</p></li><li><p>Pug(Jade) snippets pug语法提示</p></li><li><p>React Components 根据文件名创建反应组件代码。</p></li><li><p>React Native Tools reactNative工具类为React Native项目提供了开发环境。</p></li><li><p>Stylelint css/sass代码审查</p></li><li><p>Typings auto installer 安装vscode 的代码提示依赖库，基于typtings的</p></li><li><p>View In Browser 　默认浏览器查看HTML文件（快捷键Ctrl+F1可以修改）</p></li><li><p>Vscode-icons 让vscode资源目录加上图标、必备</p></li><li><p>VueHelper Vue2代码段（包括Vue2 api、vue-router2、vuex2）</p></li><li><p>Vue 2 Snippets vue必备vue代码提示</p></li><li><p>Vue-color vue语法高亮主题</p></li><li><p>Auto-Open Markdown Preview markdown文件自动开启预览</p></li><li><p>EverMonkey 印象笔记</p></li><li><p>atom one dark atom的一个高亮主题(个人推荐)</p></li></ol><h2 id="三、常用的电脑快捷键" tabindex="-1">三、常用的电脑快捷键 <a class="header-anchor" href="#三、常用的电脑快捷键" aria-label="Permalink to &quot;三、常用的电脑快捷键&quot;">​</a></h2><ol><li><p>ctrl + shift + delete 快速清除浏览器缓存</p></li><li><p>ctrl + alt + delete 快速进入任务管理器页面</p></li><li><p>window + L 快速锁定电脑</p></li><li><p>window + d 所有窗口最小化</p></li><li><p>window + e 打开我的资源管理器(我的电脑)</p></li><li><p>window + f 快速打开搜索窗口</p></li><li><p>alt + tab 快速查看打开的应用与窗口</p></li></ol>',7),r=[o];function a(s,c,d,n,h,u){return p(),i("div",null,r)}const m=l(e,[["render",a]]);export{v as __pageData,m as default};
